nd);end);mm2Toggle("💥 Fling Sheriff — flingt bis Person weg ist",false,function(state) mm2_flingSheriff=state;_G['mm2_flingSheriff']=state;if  not state then setStatus("⏳ Fling-Sheriff gestoppt");return;end setStatus("💥 Fling-Sheriff aktiv!",Color3.fromRGB(80,160,255));task.spawn(function() while mm2_flingSheriff do pcall(function() for _,plr in ipairs(Players_MM:GetPlayers()) do if  not mm2_flingSheriff then return;end if ((plr~=LP_MM) and (mm2_getRole(plr)=="sheriff")) then mm2_flingUntilGone(plr,"mm2_flingSheriff");end end end);task.wait(0.5);end end);end);mm2Section("🔫  SHERIFF TOOLS");local mm2_autoGrabGun=false;local mm2_grabConn_bp=nil;local mm2_grabConn_ws=nil;local mm2_grabConn_char=nil;local function mm2_isGunTool(obj) if ( not obj or  not obj:IsA("Tool")) then return false;end local n=obj.Name:lower();for _,nm in ipairs(MM2_GUN_NAMES) do if ((n==nm:lower()) or n:find(nm:lower())) then return true;end end return n:find("gun") or n:find("revolver") or n:find("pistol") or n:find("sheriff") or false ;end local function mm2_tryEquipGun() local myChar=LP_MM.Character;local myHum=myChar and myChar:FindFirstChildOfClass("Humanoid") ;local myHrp=myChar and myChar:FindFirstChild("HumanoidRootPart") ;if ( not myHum or  not myHrp) then return;end local myBp=LP_MM:FindFirstChild("Backpack");local gun=nil;if myBp then for _,obj in ipairs(myBp:GetChildren()) do if mm2_isGunTool(obj) then gun=obj;break;end end end if  not gun then for _,obj in ipairs(myChar:GetChildren()) do if mm2_isGunTool(obj) then gun=obj;break;end end end if gun then pcall(function() myHum:EquipTool(gun);end);return true;end for _,obj in ipairs(workspace:GetChildren()) do if mm2_isGunTool(obj) then local handle=obj:FindFirstChild("Handle");if handle then if pcall(function() myHum:EquipTool(obj);end) then return true;end myHrp.CFrame=CFrame.new(handle.Position + Vector3.new(0,3,0) );task.wait(0.08);for _,pp in ipairs(obj:GetDescendants()) do if pp:IsA("ProximityPrompt") then pcall(function() fireprox