r) if ( not gun or  not myHrp or  not tHrp) then return;end local tHead=tChar and tChar:FindFirstChild("Head") ;local aimPos=(tHead and tHead.Position) or tHrp.Position ;local mt=getrawmetatable(game);local old=mt.__index;setreadonly(mt,false);local function spoofFn(self,key) if ((self==mm2_mouse) and ((key=="Hit") or (key=="UnitRay"))) then if (key=="Hit") then return CFrame.new(aimPos);else local origin=myHrp.Position;local dir=(aimPos-origin).Unit;return Ray.new(origin,dir);end end return old(self,key);end local ok,cc=pcall(newcclosure,spoofFn);mt.__index=(ok and cc) or spoofFn ;pcall(function() gun:Activate();end);mt.__index=old;pcall(setreadonly,mt,true);end local function mm2_getGun(myChar,myHum) local myBp=LP_MM:FindFirstChild("Backpack");local gun=nil;for _,nm in ipairs(MM2_GUN_NAMES) do gun=(myBp and myBp:FindFirstChild(nm)) or (myChar and myChar:FindFirstChild(nm)) ;if gun then break;end end if ( not gun and myBp) then for _,obj in ipairs(myBp:GetChildren()) do if obj:IsA("Tool") then local n=obj.Name:lower();if (n:find("gun") or n:find("revolver") or n:find("pistol") or n:find("sheriff")) then gun=obj;break;end end end end if (gun and gun:IsA("Tool")) then pcall(function() myHum:EquipTool(gun);end);end return gun;end mm2Toggle("🔫 Auto Shoot Murder — Magic Bullet\nautomatisch, durch Wände, von dir aus",false,function(state) mm2_autoShoot=state;if  not state then setStatus("⏳ Auto-Shoot gestoppt");return;end if (mm2_getRole(LP_MM)~="sheriff") then setStatus("❌ Du bist nicht der Sheriff!",Color3.fromRGB(255,60,60));mm2_autoShoot=false;return;end setStatus("🔫 Magic Bullet aktiv!",Color3.fromRGB(60,160,255));task.spawn(function() while mm2_autoShoot do pcall(function() local myChar=LP_MM.Character;local myHum=myChar and myChar:FindFirstChildOfClass("Humanoid") ;local myHrp=myChar and myChar:FindFirstChild("HumanoidRootPart") ;if ( not myHum or  not myHrp) then return;end local gun=mm2_getGun(myChar,myHum);task.wait(0.05);for _,plr in ipairs(Players_MM:GetPlaye